const now = new Date();
const since = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const parseJsonl = (text) => String(text || '').split(/\r?\n/).map(line => line.trim()).filter(Boolean).map(line => { try { return JSON.parse(line); } catch { return null; } }).filter(Boolean);
const traffic = parseJsonl($('Read Traffic Log').item.json.stdout || '').filter(e => e.timestamp && new Date(e.timestamp) >= since);
const serviceRequests = parseJsonl($('Read Service Request Log').item.json.stdout || '').filter(e => e.timestamp && new Date(e.timestamp) >= since);
const pageViews = traffic.filter(e => (e.event_type || 'page_view') === 'page_view');
const leadEvents = traffic.filter(e => e.event_type === 'lead_submit');
const sessions = new Set(pageViews.map(e => e.session_id || e.visitor_id || e.page_url).filter(Boolean));
const visitors = new Set(pageViews.map(e => e.visitor_id || e.session_id || e.page_url).filter(Boolean));
const isMeta = (item) => {
  const text = [item.utm_source, item.utm_medium, item.referrer, item.fbclid, item.source_site, item.landing_url, item.source_url, item.page_url].filter(Boolean).join(' ').toLowerCase();
  return Boolean(item.is_meta_traffic || text.match(/facebook|instagram|meta|fbclid|l\.facebook|lm\.facebook|m\.facebook|l\.instagram/));
};
const metaViews = pageViews.filter(isMeta);
const metaSessions = new Set(metaViews.map(e => e.session_id || e.visitor_id || e.page_url).filter(Boolean));
const metaLeadEvents = leadEvents.filter(isMeta);
const countBy = (items, fn) => {
  const map = new Map();
  for (const item of items) {
    const key = fn(item) || '(not set)';
    map.set(key, (map.get(key) || 0) + 1);
  }
  return Array.from(map.entries()).sort((a, b) => b[1] - a[1]);
};
const pathFrom = (e) => {
  if (e.path) return e.path;
  try { return new URL(e.page_url).pathname || '/'; } catch { return e.page_url || '/'; }
};
const topPages = countBy(pageViews, pathFrom).slice(0, 5);
const referrers = countBy(pageViews.filter(e => e.referrer), e => { try { return new URL(e.referrer).hostname.replace(/^www\./, ''); } catch { return e.referrer; } }).slice(0, 5);
const campaigns = countBy(pageViews.filter(e => e.utm_campaign), e => e.utm_campaign).slice(0, 5);
const services = countBy(serviceRequests, e => e.requested_service || e.service || 'General Inquiry').slice(0, 5);
const fmtList = (pairs) => pairs.length ? pairs.map(([k, v]) => `- ${k}: ${v}`).join('\n') : '- No data yet';
const rate = sessions.size ? ((leadEvents.length / sessions.size) * 100).toFixed(1) + '%' : 'n/a';
const metaRate = metaSessions.size ? ((metaLeadEvents.length / metaSessions.size) * 100).toFixed(1) + '%' : 'n/a';
const lines = [];
lines.push('*GT Website Traffic Executive Summary*');
lines.push(now.toLocaleString('en-US', { timeZone: 'America/New_York', weekday: 'long', month: 'long', day: 'numeric', year: 'numeric', hour: 'numeric', minute: '2-digit' }));
lines.push('');
lines.push('*Last 24 Hours*');
lines.push(`- Tracked page views: ${pageViews.length}`);
lines.push(`- Tracked sessions: ${sessions.size}`);
lines.push(`- Tracked visitors: ${visitors.size}`);
lines.push(`- Tracked form submits: ${leadEvents.length} (${rate} session-to-submit)`);
lines.push(`- Service-request records: ${serviceRequests.length}`);
lines.push(`- Meta/Facebook/Instagram sessions: ${metaSessions.size}; tracked form submits: ${metaLeadEvents.length} (${metaRate})`);
lines.push('');
lines.push('*Top Pages*');
lines.push(fmtList(topPages));
lines.push('');
lines.push('*Top Referrers*');
lines.push(fmtList(referrers));
lines.push('');
lines.push('*Campaigns*');
lines.push(fmtList(campaigns));
lines.push('');
lines.push('*Lead Mix*');
lines.push(fmtList(services));
lines.push('');
lines.push('*Readout*');
if (!pageViews.length) {
  lines.push('- No traffic events logged in the last 24 hours. Confirm the collector workflow is active and the public site is deployed.');
} else if (metaSessions.size && !metaLeadEvents.length) {
  lines.push('- Meta traffic is arriving but has not produced a tracked form submit in this window. Check landing-page/service fit and ad promise.');
} else if (metaLeadEvents.length) {
  lines.push('- Meta traffic produced at least one tracked form submit. Review campaign/ad labels before increasing spend.');
} else {
  lines.push('- Organic/direct traffic is the current visible source. Meta attribution will show when UTM or fbclid traffic arrives.');
}
return [{ json: { slackChannel: $env.EXECUTIVE_SUMMARY_SLACK_CHANNEL || '#alfred-ops', slackText: lines.join('\n'), windowStart: since.toISOString(), windowEnd: now.toISOString(), pageViews: pageViews.length, sessions: sessions.size, leadEvents: leadEvents.length, serviceRequests: serviceRequests.length, metaSessions: metaSessions.size, metaLeadEvents: metaLeadEvents.length } }];
